def find_second_largest(numbers: list[int]) -> int:
    if len(set(numbers)) < 2:
        raise ValueError("Need at least 2 unique values")
    first = second = float('-inf')
    for n in numbers:
        if n > first:
            second = first
            first = n
        elif n > second and n != first:
            second = n
    return second
